// Package aws implements the AWS EC2 VM provider. It provisions an instance via
// a CloudFormation stack, resolves the AMI through SSM Parameter Store, discovers
// or creates VPC/subnet infrastructure via EC2, and manages Route53 DNS records.
//
// External AWS calls go through small interfaces (ssmAPI, ec2API, cfnAPI,
// route53API) that wrap only the SDK methods used here, so the orchestration
// logic is unit-testable with fakes and no network access.
package aws

import (
	"context"
	"fmt"

	awssdk "github.com/aws/aws-sdk-go-v2/aws"
	awsconfig "github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/service/cloudformation"
	"github.com/aws/aws-sdk-go-v2/service/ec2"
	"github.com/aws/aws-sdk-go-v2/service/route53"
	"github.com/aws/aws-sdk-go-v2/service/ssm"
)

// ssmAPI wraps the SSM Parameter Store call used for AMI lookup.
type ssmAPI interface {
	GetParameter(ctx context.Context, in *ssm.GetParameterInput, optFns ...func(*ssm.Options)) (*ssm.GetParameterOutput, error)
}

// ec2API wraps the EC2 calls used for VPC/subnet discovery, instance lifecycle,
// and network resource cleanup.
type ec2API interface {
	DescribeVpcs(ctx context.Context, in *ec2.DescribeVpcsInput, optFns ...func(*ec2.Options)) (*ec2.DescribeVpcsOutput, error)
	DescribeSubnets(ctx context.Context, in *ec2.DescribeSubnetsInput, optFns ...func(*ec2.Options)) (*ec2.DescribeSubnetsOutput, error)
	CreateVpc(ctx context.Context, in *ec2.CreateVpcInput, optFns ...func(*ec2.Options)) (*ec2.CreateVpcOutput, error)
	CreateSubnet(ctx context.Context, in *ec2.CreateSubnetInput, optFns ...func(*ec2.Options)) (*ec2.CreateSubnetOutput, error)
	ModifySubnetAttribute(ctx context.Context, in *ec2.ModifySubnetAttributeInput, optFns ...func(*ec2.Options)) (*ec2.ModifySubnetAttributeOutput, error)
	CreateInternetGateway(ctx context.Context, in *ec2.CreateInternetGatewayInput, optFns ...func(*ec2.Options)) (*ec2.CreateInternetGatewayOutput, error)
	AttachInternetGateway(ctx context.Context, in *ec2.AttachInternetGatewayInput, optFns ...func(*ec2.Options)) (*ec2.AttachInternetGatewayOutput, error)
	CreateRouteTable(ctx context.Context, in *ec2.CreateRouteTableInput, optFns ...func(*ec2.Options)) (*ec2.CreateRouteTableOutput, error)
	CreateRoute(ctx context.Context, in *ec2.CreateRouteInput, optFns ...func(*ec2.Options)) (*ec2.CreateRouteOutput, error)
	AssociateRouteTable(ctx context.Context, in *ec2.AssociateRouteTableInput, optFns ...func(*ec2.Options)) (*ec2.AssociateRouteTableOutput, error)
	DescribeInstances(ctx context.Context, in *ec2.DescribeInstancesInput, optFns ...func(*ec2.Options)) (*ec2.DescribeInstancesOutput, error)
	StopInstances(ctx context.Context, in *ec2.StopInstancesInput, optFns ...func(*ec2.Options)) (*ec2.StopInstancesOutput, error)
	StartInstances(ctx context.Context, in *ec2.StartInstancesInput, optFns ...func(*ec2.Options)) (*ec2.StartInstancesOutput, error)
	DisassociateRouteTable(ctx context.Context, in *ec2.DisassociateRouteTableInput, optFns ...func(*ec2.Options)) (*ec2.DisassociateRouteTableOutput, error)
	DeleteRouteTable(ctx context.Context, in *ec2.DeleteRouteTableInput, optFns ...func(*ec2.Options)) (*ec2.DeleteRouteTableOutput, error)
	DetachInternetGateway(ctx context.Context, in *ec2.DetachInternetGatewayInput, optFns ...func(*ec2.Options)) (*ec2.DetachInternetGatewayOutput, error)
	DeleteInternetGateway(ctx context.Context, in *ec2.DeleteInternetGatewayInput, optFns ...func(*ec2.Options)) (*ec2.DeleteInternetGatewayOutput, error)
	DeleteSubnet(ctx context.Context, in *ec2.DeleteSubnetInput, optFns ...func(*ec2.Options)) (*ec2.DeleteSubnetOutput, error)
	DeleteVpc(ctx context.Context, in *ec2.DeleteVpcInput, optFns ...func(*ec2.Options)) (*ec2.DeleteVpcOutput, error)
}

// cfnAPI wraps the CloudFormation calls used for stack lifecycle.
type cfnAPI interface {
	CreateStack(ctx context.Context, in *cloudformation.CreateStackInput, optFns ...func(*cloudformation.Options)) (*cloudformation.CreateStackOutput, error)
	DescribeStacks(ctx context.Context, in *cloudformation.DescribeStacksInput, optFns ...func(*cloudformation.Options)) (*cloudformation.DescribeStacksOutput, error)
	DeleteStack(ctx context.Context, in *cloudformation.DeleteStackInput, optFns ...func(*cloudformation.Options)) (*cloudformation.DeleteStackOutput, error)
}

// route53API wraps the Route53 calls used for hosted-zone lookup and record
// management.
type route53API interface {
	ListHostedZonesByName(ctx context.Context, in *route53.ListHostedZonesByNameInput, optFns ...func(*route53.Options)) (*route53.ListHostedZonesByNameOutput, error)
	ChangeResourceRecordSets(ctx context.Context, in *route53.ChangeResourceRecordSetsInput, optFns ...func(*route53.Options)) (*route53.ChangeResourceRecordSetsOutput, error)
}

// clients bundles the AWS service clients used by the provider.
type clients struct {
	ssm     ssmAPI
	ec2     ec2API
	cfn     cfnAPI
	route53 route53API
}

// loadClients builds AWS service clients from the default credential chain for
// the given region. Route53 is a global service; its client uses the same
// loaded config. A missing or unresolvable credential set surfaces as an
// actionable error rather than failing later at the first API call.
func loadClients(ctx context.Context, region string) (*clients, error) {
	cfg, err := awsconfig.LoadDefaultConfig(ctx, awsconfig.WithRegion(region))
	if err != nil {
		return nil, fmt.Errorf("AWS credentials not configured: run 'aws configure': %w", err)
	}
	// Retrieve credentials eagerly so missing/invalid credentials produce the
	// actionable error here instead of deep inside an unrelated API call.
	if cfg.Credentials == nil {
		return nil, fmt.Errorf("AWS credentials not configured: run 'aws configure'")
	}
	if _, err := cfg.Credentials.Retrieve(ctx); err != nil {
		return nil, fmt.Errorf("AWS credentials not configured: run 'aws configure': %w", err)
	}
	return &clients{
		ssm:     ssm.NewFromConfig(cfg),
		ec2:     ec2.NewFromConfig(cfg),
		cfn:     cloudformation.NewFromConfig(cfg),
		route53: route53.NewFromConfig(cfg),
	}, nil
}

// ptr returns a pointer to v. It mirrors awssdk.String/Bool/Int helpers for
// types those do not cover, keeping call sites terse.
func ptr[T any](v T) *T { return &v }

// ensure the aws helper import is retained for callers in sibling files.
var _ = awssdk.String

package aws

import (
	"context"
	"fmt"

	awssdk "github.com/aws/aws-sdk-go-v2/aws"
	"github.com/aws/aws-sdk-go-v2/service/ssm"
)

// ssmPaths maps a vm.os key to the SSM Parameter Store path whose value is the
// latest AMI ID for that OS in the target region.
var ssmPaths = map[string]string{
	"ubuntu-24.04":      "/aws/service/canonical/ubuntu/server/24.04/stable/current/amd64/hvm/ebs-gp2/ami-id",
	"ubuntu-22.04":      "/aws/service/canonical/ubuntu/server/22.04/stable/current/amd64/hvm/ebs-gp2/ami-id",
	"ubuntu-20.04":      "/aws/service/canonical/ubuntu/server/20.04/stable/current/amd64/hvm/ebs-gp2/ami-id",
	"amazon-linux-2023": "/aws/service/ami-amazon-linux-latest/al2023-ami-kernel-default-x86_64",
	"amazon-linux-2":    "/aws/service/ami-amazon-linux-latest/amzn2-ami-hvm-x86_64-gp2",
	"debian-12":         "/aws/service/debian/release/12/latest/amd64",
	"debian-11":         "/aws/service/debian/release/11/latest/amd64",
}

// ssmPath resolves an os key to its SSM Parameter Store path. Unknown keys are
// an error listing the value supplied.
func ssmPath(os string) (string, error) {
	path, ok := ssmPaths[os]
	if !ok {
		return "", fmt.Errorf("unknown os %q: supported values are ubuntu-24.04, ubuntu-22.04, ubuntu-20.04, amazon-linux-2023, amazon-linux-2, debian-12, debian-11", os)
	}
	return path, nil
}

// lookupAMI resolves the AMI ID for an os key via SSM Parameter Store.
func lookupAMI(ctx context.Context, api ssmAPI, os string) (string, error) {
	path, err := ssmPath(os)
	if err != nil {
		return "", err
	}
	out, err := api.GetParameter(ctx, &ssm.GetParameterInput{Name: awssdk.String(path)})
	if err != nil {
		return "", fmt.Errorf("looking up AMI for %q via SSM %s: %w", os, path, err)
	}
	if out.Parameter == nil || out.Parameter.Value == nil || *out.Parameter.Value == "" {
		return "", fmt.Errorf("SSM parameter %s returned no AMI ID", path)
	}
	return *out.Parameter.Value, nil
}

package aws

import (
	"context"
	"fmt"
	"time"

	awssdk "github.com/aws/aws-sdk-go-v2/aws"
	"github.com/aws/aws-sdk-go-v2/service/ec2"
	ec2types "github.com/aws/aws-sdk-go-v2/service/ec2/types"

	"github.com/gherlein/govirt/internal/config"
)

// newVpcCidr is the CIDR for a VPC govirt creates when no usable VPC exists.
const newVpcCidr = "10.0.0.0/16"

// newSubnetCidr is the CIDR for a subnet govirt creates inside a new VPC.
const newSubnetCidr = "10.0.1.0/24"

// network holds the discovered or created VPC/subnet plus any resources govirt
// created so they can be recorded in state and cleaned up on destroy.
type network struct {
	VpcID                 string
	SubnetID              string
	CreatedVPC            bool
	CreatedSubnet         bool
	InternetGatewayID     string
	RouteTableID          string
	RouteTableAssociation string
}

// ensureNetwork resolves the VPC and subnet to launch into. Explicit vm.vpc_id
// and vm.subnet_id short-circuit discovery. Otherwise it follows the documented
// order: default VPC, then any available VPC, then create a full VPC stack;
// within the chosen VPC it finds a public-auto-assign subnet or creates one.
func ensureNetwork(ctx context.Context, api ec2API, vm *config.VMConfig) (*network, error) {
	if vm.VpcID != "" && vm.SubnetID != "" {
		return &network{VpcID: vm.VpcID, SubnetID: vm.SubnetID}, nil
	}

	vpcID := vm.VpcID
	if vpcID == "" {
		discovered, created, err := discoverOrCreateVPC(ctx, api)
		if err != nil {
			return nil, err
		}
		return finishNetwork(ctx, api, discovered, created)
	}

	subnetID, err := findPublicSubnet(ctx, api, vpcID)
	if err != nil {
		return nil, err
	}
	if subnetID == "" {
		net := &network{VpcID: vpcID}
		if err := createSubnetWithRouting(ctx, api, net, false); err != nil {
			return nil, err
		}
		return net, nil
	}
	return &network{VpcID: vpcID, SubnetID: subnetID}, nil
}

// finishNetwork resolves a subnet inside an already-chosen VPC. For a VPC govirt
// just created, routing (IGW + route table) is provisioned alongside the subnet.
func finishNetwork(ctx context.Context, api ec2API, net *network, createdVPC bool) (*network, error) {
	net.CreatedVPC = createdVPC
	if !createdVPC {
		subnetID, err := findPublicSubnet(ctx, api, net.VpcID)
		if err != nil {
			return nil, err
		}
		if subnetID != "" {
			net.SubnetID = subnetID
			return net, nil
		}
	}
	if err := createSubnetWithRouting(ctx, api, net, createdVPC); err != nil {
		return nil, err
	}
	return net, nil
}

// discoverOrCreateVPC returns the default VPC, else any available VPC, else a
// freshly created VPC. The boolean reports whether the VPC was created.
func discoverOrCreateVPC(ctx context.Context, api ec2API) (*network, bool, error) {
	defaultVpc, err := api.DescribeVpcs(ctx, &ec2.DescribeVpcsInput{
		Filters: []ec2types.Filter{{Name: awssdk.String("is-default"), Values: []string{"true"}}},
	})
	if err != nil {
		return nil, false, fmt.Errorf("describing default VPC: %w", err)
	}
	if id := firstAvailableVpc(defaultVpc.Vpcs); id != "" {
		return &network{VpcID: id}, false, nil
	}

	all, err := api.DescribeVpcs(ctx, &ec2.DescribeVpcsInput{})
	if err != nil {
		return nil, false, fmt.Errorf("describing VPCs: %w", err)
	}
	if id := firstAvailableVpc(all.Vpcs); id != "" {
		return &network{VpcID: id}, false, nil
	}

	net := &network{}
	created, err := api.CreateVpc(ctx, &ec2.CreateVpcInput{CidrBlock: awssdk.String(newVpcCidr)})
	if err != nil {
		return nil, false, fmt.Errorf("creating VPC: %w", err)
	}
	net.VpcID = awssdk.ToString(created.Vpc.VpcId)
	return net, true, nil
}

// firstAvailableVpc returns the ID of the first VPC in the available state, or
// "" when none qualifies.
func firstAvailableVpc(vpcs []ec2types.Vpc) string {
	for _, v := range vpcs {
		if v.State == ec2types.VpcStateAvailable && v.VpcId != nil {
			return *v.VpcId
		}
	}
	return ""
}

// findPublicSubnet returns the first subnet in the VPC that auto-assigns public
// IPs, or "" if none does.
func findPublicSubnet(ctx context.Context, api ec2API, vpcID string) (string, error) {
	out, err := api.DescribeSubnets(ctx, &ec2.DescribeSubnetsInput{
		Filters: []ec2types.Filter{{Name: awssdk.String("vpc-id"), Values: []string{vpcID}}},
	})
	if err != nil {
		return "", fmt.Errorf("describing subnets for %s: %w", vpcID, err)
	}
	return firstPublicSubnet(out.Subnets), nil
}

// firstPublicSubnet returns the ID of the first available subnet with public IP
// auto-assignment enabled.
func firstPublicSubnet(subnets []ec2types.Subnet) string {
	for _, s := range subnets {
		if s.SubnetId == nil {
			continue
		}
		if awssdk.ToBool(s.MapPublicIpOnLaunch) && s.State == ec2types.SubnetStateAvailable {
			return *s.SubnetId
		}
	}
	return ""
}

// createSubnetWithRouting creates a public subnet in net.VpcID. When the VPC was
// just created by govirt, it also creates and attaches an Internet Gateway and a
// route table with a default route so the subnet is genuinely internet-facing.
// All created resources are recorded on net for cleanup.
func createSubnetWithRouting(ctx context.Context, api ec2API, net *network, createdVPC bool) error {
	subnet, err := api.CreateSubnet(ctx, &ec2.CreateSubnetInput{
		VpcId:     awssdk.String(net.VpcID),
		CidrBlock: awssdk.String(newSubnetCidr),
	})
	if err != nil {
		return fmt.Errorf("creating subnet: %w", err)
	}
	net.SubnetID = awssdk.ToString(subnet.Subnet.SubnetId)
	net.CreatedSubnet = true

	if _, err := api.ModifySubnetAttribute(ctx, &ec2.ModifySubnetAttributeInput{
		SubnetId:            awssdk.String(net.SubnetID),
		MapPublicIpOnLaunch: &ec2types.AttributeBooleanValue{Value: awssdk.Bool(true)},
	}); err != nil {
		return fmt.Errorf("enabling public IP auto-assign on subnet: %w", err)
	}

	if !createdVPC {
		return nil
	}

	igw, err := api.CreateInternetGateway(ctx, &ec2.CreateInternetGatewayInput{})
	if err != nil {
		return fmt.Errorf("creating internet gateway: %w", err)
	}
	net.InternetGatewayID = awssdk.ToString(igw.InternetGateway.InternetGatewayId)
	if _, err := api.AttachInternetGateway(ctx, &ec2.AttachInternetGatewayInput{
		InternetGatewayId: awssdk.String(net.InternetGatewayID),
		VpcId:             awssdk.String(net.VpcID),
	}); err != nil {
		return fmt.Errorf("attaching internet gateway: %w", err)
	}

	rt, err := api.CreateRouteTable(ctx, &ec2.CreateRouteTableInput{VpcId: awssdk.String(net.VpcID)})
	if err != nil {
		return fmt.Errorf("creating route table: %w", err)
	}
	net.RouteTableID = awssdk.ToString(rt.RouteTable.RouteTableId)
	if _, err := api.CreateRoute(ctx, &ec2.CreateRouteInput{
		RouteTableId:         awssdk.String(net.RouteTableID),
		DestinationCidrBlock: awssdk.String("0.0.0.0/0"),
		GatewayId:            awssdk.String(net.InternetGatewayID),
	}); err != nil {
		return fmt.Errorf("creating default route: %w", err)
	}
	assoc, err := api.AssociateRouteTable(ctx, &ec2.AssociateRouteTableInput{
		RouteTableId: awssdk.String(net.RouteTableID),
		SubnetId:     awssdk.String(net.SubnetID),
	})
	if err != nil {
		return fmt.Errorf("associating route table: %w", err)
	}
	net.RouteTableAssociation = awssdk.ToString(assoc.AssociationId)
	return nil
}

// applyNetworkState records discovered/created network resources into AWS state.
func applyNetworkState(state *config.AWSState, net *network) {
	state.VpcID = net.VpcID
	state.SubnetID = net.SubnetID
	state.CreatedVPC = net.CreatedVPC
	state.CreatedSubnet = net.CreatedSubnet
	state.InternetGatewayID = net.InternetGatewayID
	state.RouteTableID = net.RouteTableID
	state.RouteTableAssociation = net.RouteTableAssociation
}

// cleanupNetwork deletes only the network resources govirt created, in reverse
// dependency order. Errors are returned for the caller to surface but each step
// is attempted regardless of earlier failures so partial cleanup can proceed.
func cleanupNetwork(ctx context.Context, api ec2API, state *config.AWSState) error {
	var firstErr error
	record := func(err error) {
		if err != nil && firstErr == nil {
			firstErr = err
		}
	}

	if state.RouteTableAssociation != "" {
		_, err := api.DisassociateRouteTable(ctx, &ec2.DisassociateRouteTableInput{
			AssociationId: awssdk.String(state.RouteTableAssociation),
		})
		record(err)
	}
	if state.RouteTableID != "" {
		_, err := api.DeleteRouteTable(ctx, &ec2.DeleteRouteTableInput{
			RouteTableId: awssdk.String(state.RouteTableID),
		})
		record(err)
	}
	if state.InternetGatewayID != "" && state.VpcID != "" {
		_, err := api.DetachInternetGateway(ctx, &ec2.DetachInternetGatewayInput{
			InternetGatewayId: awssdk.String(state.InternetGatewayID),
			VpcId:             awssdk.String(state.VpcID),
		})
		record(err)
		_, err = api.DeleteInternetGateway(ctx, &ec2.DeleteInternetGatewayInput{
			InternetGatewayId: awssdk.String(state.InternetGatewayID),
		})
		record(err)
	}
	if state.CreatedSubnet && state.SubnetID != "" {
		_, err := api.DeleteSubnet(ctx, &ec2.DeleteSubnetInput{SubnetId: awssdk.String(state.SubnetID)})
		record(err)
	}
	if state.CreatedVPC && state.VpcID != "" {
		_, err := api.DeleteVpc(ctx, &ec2.DeleteVpcInput{VpcId: awssdk.String(state.VpcID)})
		record(err)
	}
	return firstErr
}

// describeInstance returns the EC2 instance matching id, or an error if it is
// absent.
func describeInstance(ctx context.Context, api ec2API, id string) (*ec2types.Instance, error) {
	out, err := api.DescribeInstances(ctx, &ec2.DescribeInstancesInput{InstanceIds: []string{id}})
	if err != nil {
		return nil, fmt.Errorf("describing instance %s: %w", id, err)
	}
	for _, r := range out.Reservations {
		for i := range r.Instances {
			return &r.Instances[i], nil
		}
	}
	return nil, fmt.Errorf("instance %s not found", id)
}

// instanceStatus normalizes an EC2 instance into a provider VMStatus.
func instanceStatus(inst *ec2types.Instance, name string) (state, ip string, created time.Time) {
	if inst.State != nil {
		state = string(inst.State.Name)
	}
	ip = awssdk.ToString(inst.PublicIpAddress)
	if inst.LaunchTime != nil {
		created = *inst.LaunchTime
	}
	return state, ip, created
}

package aws

import (
	"encoding/json"
	"fmt"
)

// stackName returns the CloudFormation stack name for a VM. Callers must have
// validated name with config.ValidateName first; the grammar excludes any
// character that is unsafe in a stack name.
func stackName(name string) string {
	return "govirt-" + name
}

// templateParams are the inputs to the CloudFormation template generator.
type templateParams struct {
	AMIID        string
	InstanceType string
	SubnetID     string
	VpcID        string
	UserDataB64  string
	SSHCidr      string
	WebCidr      string
}

// renderTemplate produces a CloudFormation template (JSON) that creates a
// security group allowing inbound TCP 22, 80, and 443, and an EC2 instance in
// the given subnet with a public IP and the supplied base64 cloud-init
// UserData. It exposes InstanceId, PublicIP, and SecurityGroupId as outputs.
func renderTemplate(p templateParams) (string, error) {
	sshCidr := p.SSHCidr
	if sshCidr == "" {
		sshCidr = "0.0.0.0/0"
	}
	webCidr := p.WebCidr
	if webCidr == "" {
		webCidr = "0.0.0.0/0"
	}

	ingress := []map[string]any{
		ingressRule(22, sshCidr),
		ingressRule(80, webCidr),
		ingressRule(443, webCidr),
	}

	tmpl := map[string]any{
		"AWSTemplateFormatVersion": "2010-09-09",
		"Description":              "govirt-managed EC2 instance and security group",
		"Resources": map[string]any{
			"InstanceSecurityGroup": map[string]any{
				"Type": "AWS::EC2::SecurityGroup",
				"Properties": map[string]any{
					"GroupDescription":     "govirt instance security group",
					"VpcId":                p.VpcID,
					"SecurityGroupIngress": ingress,
				},
			},
			"Instance": map[string]any{
				"Type": "AWS::EC2::Instance",
				"Properties": map[string]any{
					"ImageId":      p.AMIID,
					"InstanceType": p.InstanceType,
					"UserData":     p.UserDataB64,
					"NetworkInterfaces": []map[string]any{
						{
							"DeviceIndex":              "0",
							"AssociatePublicIpAddress": true,
							"SubnetId":                 p.SubnetID,
							"GroupSet":                 []any{map[string]any{"Ref": "InstanceSecurityGroup"}},
						},
					},
				},
			},
		},
		"Outputs": map[string]any{
			"InstanceId": map[string]any{
				"Value": map[string]any{"Ref": "Instance"},
			},
			"PublicIP": map[string]any{
				"Value": map[string]any{"Fn::GetAtt": []any{"Instance", "PublicIp"}},
			},
			"SecurityGroupId": map[string]any{
				"Value": map[string]any{"Fn::GetAtt": []any{"InstanceSecurityGroup", "GroupId"}},
			},
		},
	}

	out, err := json.MarshalIndent(tmpl, "", "  ")
	if err != nil {
		return "", fmt.Errorf("marshaling CloudFormation template: %w", err)
	}
	return string(out), nil
}

// ingressRule builds a single TCP ingress rule for the security group.
func ingressRule(port int, cidr string) map[string]any {
	return map[string]any{
		"IpProtocol": "tcp",
		"FromPort":   port,
		"ToPort":     port,
		"CidrIp":     cidr,
	}
}

package aws

import (
	"context"
	"fmt"
	"time"

	awssdk "github.com/aws/aws-sdk-go-v2/aws"
	"github.com/aws/aws-sdk-go-v2/service/cloudformation"
	cfntypes "github.com/aws/aws-sdk-go-v2/service/cloudformation/types"
)

// stackPoll controls how long createStack waits for CREATE_COMPLETE.
type stackPoll struct {
	interval time.Duration
	timeout  time.Duration
}

var defaultStackPoll = stackPoll{interval: 10 * time.Second, timeout: 15 * time.Minute}

// stackOutputs holds the values parsed from a completed stack's outputs.
type stackOutputs struct {
	InstanceID      string
	PublicIP        string
	SecurityGroupID string
}

// createStack creates the CloudFormation stack, polls DescribeStacks until it
// reaches CREATE_COMPLETE, and returns the stack ID and parsed outputs. A
// terminal failure status (e.g. CREATE_FAILED, ROLLBACK_COMPLETE) is an error.
func createStack(ctx context.Context, api cfnAPI, name, templateBody string, poll stackPoll) (string, *stackOutputs, error) {
	created, err := api.CreateStack(ctx, &cloudformation.CreateStackInput{
		StackName:    awssdk.String(name),
		TemplateBody: awssdk.String(templateBody),
	})
	if err != nil {
		return "", nil, fmt.Errorf("creating stack %s: %w", name, err)
	}
	stackID := awssdk.ToString(created.StackId)

	deadline := time.Now().Add(poll.timeout)
	for {
		stack, err := describeStack(ctx, api, name)
		if err != nil {
			return stackID, nil, err
		}
		switch stack.StackStatus {
		case cfntypes.StackStatusCreateComplete:
			outputs := parseStackOutputs(stack.Outputs)
			return stackID, outputs, nil
		case cfntypes.StackStatusCreateInProgress:
			// keep waiting
		default:
			return stackID, nil, fmt.Errorf("stack %s entered terminal state %s: %s",
				name, stack.StackStatus, awssdk.ToString(stack.StackStatusReason))
		}
		if time.Now().After(deadline) {
			return stackID, nil, fmt.Errorf("stack %s did not reach CREATE_COMPLETE within %s", name, poll.timeout)
		}
		select {
		case <-ctx.Done():
			return stackID, nil, ctx.Err()
		case <-time.After(poll.interval):
		}
	}
}

// describeStack returns the single stack matching name.
func describeStack(ctx context.Context, api cfnAPI, name string) (*cfntypes.Stack, error) {
	out, err := api.DescribeStacks(ctx, &cloudformation.DescribeStacksInput{StackName: awssdk.String(name)})
	if err != nil {
		return nil, fmt.Errorf("describing stack %s: %w", name, err)
	}
	if len(out.Stacks) == 0 {
		return nil, fmt.Errorf("stack %s not found", name)
	}
	return &out.Stacks[0], nil
}

// parseStackOutputs extracts the InstanceId, PublicIP, and SecurityGroupId
// values from CloudFormation stack outputs.
func parseStackOutputs(outputs []cfntypes.Output) *stackOutputs {
	result := &stackOutputs{}
	for _, o := range outputs {
		key := awssdk.ToString(o.OutputKey)
		value := awssdk.ToString(o.OutputValue)
		switch key {
		case "InstanceId":
			result.InstanceID = value
		case "PublicIP":
			result.PublicIP = value
		case "SecurityGroupId":
			result.SecurityGroupID = value
		}
	}
	return result
}

// deleteStack requests stack deletion. It does not wait for completion; network
// cleanup that depends on the stack being gone is the caller's responsibility.
func deleteStack(ctx context.Context, api cfnAPI, name string) error {
	if _, err := api.DeleteStack(ctx, &cloudformation.DeleteStackInput{StackName: awssdk.String(name)}); err != nil {
		return fmt.Errorf("deleting stack %s: %w", name, err)
	}
	return nil
}

package aws

import (
	"context"
	"fmt"
	"strings"

	awssdk "github.com/aws/aws-sdk-go-v2/aws"
	"github.com/aws/aws-sdk-go-v2/service/route53"
	r53types "github.com/aws/aws-sdk-go-v2/service/route53/types"

	"github.com/gherlein/govirt/internal/config"
)

// recordSpec describes a single DNS record govirt manages.
type recordSpec struct {
	Name  string
	Type  string
	Value string
	TTL   int64
}

// planRecords builds the set of Route53 records to create for a deployment: the
// hostname A record, an apex A record when requested, and a CNAME per alias
// pointing at the hostname FQDN. publicIP is the A-record target.
func planRecords(dns *config.DNSConfig, publicIP string) []recordSpec {
	domain := strings.TrimSuffix(dns.Domain, ".")
	hostFQDN := fqdn(dns.Hostname, domain)
	ttl := int64(dns.TTL)
	if ttl == 0 {
		ttl = config.DefaultTTL
	}

	specs := []recordSpec{
		{Name: hostFQDN, Type: "A", Value: publicIP, TTL: ttl},
	}
	if dns.IsApexDomain {
		specs = append(specs, recordSpec{Name: domain + ".", Type: "A", Value: publicIP, TTL: ttl})
	}
	for _, alias := range dns.CNAMEAliases {
		specs = append(specs, recordSpec{
			Name:  fqdn(alias, domain),
			Type:  "CNAME",
			Value: hostFQDN,
			TTL:   ttl,
		})
	}
	return specs
}

// fqdn joins a hostname and domain into a trailing-dot FQDN. An apex hostname
// (equal to the domain or empty) yields the bare domain.
func fqdn(host, domain string) string {
	host = strings.TrimSuffix(host, ".")
	if host == "" || host == domain {
		return domain + "."
	}
	return host + "." + domain + "."
}

// lookupZoneID resolves the hosted zone ID for a domain via
// ListHostedZonesByName, choosing an exact name match. The returned ID has the
// "/hostedzone/" prefix stripped.
func lookupZoneID(ctx context.Context, api route53API, domain string) (string, error) {
	name := strings.TrimSuffix(domain, ".") + "."
	out, err := api.ListHostedZonesByName(ctx, &route53.ListHostedZonesByNameInput{
		DNSName: awssdk.String(name),
	})
	if err != nil {
		return "", fmt.Errorf("looking up hosted zone for %s: %w", domain, err)
	}
	for _, z := range out.HostedZones {
		if awssdk.ToString(z.Name) == name {
			return strings.TrimPrefix(awssdk.ToString(z.Id), "/hostedzone/"), nil
		}
	}
	return "", fmt.Errorf("no Route53 hosted zone found for domain %s", domain)
}

// changeRecord submits a single record change (action is CREATE, DELETE, or
// UPSERT) to a hosted zone.
func changeRecord(ctx context.Context, api route53API, zoneID string, action r53types.ChangeAction, spec recordSpec) error {
	_, err := api.ChangeResourceRecordSets(ctx, &route53.ChangeResourceRecordSetsInput{
		HostedZoneId: awssdk.String(zoneID),
		ChangeBatch: &r53types.ChangeBatch{
			Changes: []r53types.Change{
				{
					Action:            action,
					ResourceRecordSet: resourceRecordSet(spec),
				},
			},
		},
	})
	if err != nil {
		return fmt.Errorf("%s record %s (%s): %w", strings.ToLower(string(action)), spec.Name, spec.Type, err)
	}
	return nil
}

// resourceRecordSet converts a recordSpec to the SDK record-set type.
func resourceRecordSet(spec recordSpec) *r53types.ResourceRecordSet {
	rrType := r53types.RRTypeA
	if strings.EqualFold(spec.Type, "CNAME") {
		rrType = r53types.RRTypeCname
	}
	return &r53types.ResourceRecordSet{
		Name:            awssdk.String(spec.Name),
		Type:            rrType,
		TTL:             awssdk.Int64(spec.TTL),
		ResourceRecords: []r53types.ResourceRecord{{Value: awssdk.String(spec.Value)}},
	}
}

package aws

import (
	"context"
	"fmt"

	r53types "github.com/aws/aws-sdk-go-v2/service/route53/types"

	"github.com/gherlein/govirt/internal/config"
)

// createDNS resolves the hosted zone (when not pinned in config), creates all
// planned records pointing at publicIP, and records them in AWS state for later
// deletion. It is a no-op when no dns section is present.
func createDNS(ctx context.Context, api route53API, cfg *config.Config, publicIP string) error {
	if cfg.DNS == nil || cfg.DNS.Domain == "" {
		return nil
	}
	zoneID := cfg.DNS.ZoneID
	if zoneID == "" {
		id, err := lookupZoneID(ctx, api, cfg.DNS.Domain)
		if err != nil {
			return err
		}
		zoneID = id
	}

	specs := planRecords(cfg.DNS, publicIP)
	for _, spec := range specs {
		if err := changeRecord(ctx, api, zoneID, r53types.ChangeActionUpsert, spec); err != nil {
			return err
		}
		cfg.AWS.DNSRecords = append(cfg.AWS.DNSRecords, config.DNSRecord{Name: spec.Name, Type: spec.Type})
	}
	cfg.AWS.ZoneID = zoneID
	cfg.AWS.FQDN = fqdn(cfg.DNS.Hostname, cfg.DNS.Domain)
	return nil
}

// deleteDNS deletes every tracked record. Route53 DELETE requires the record's
// full definition, which is re-derived from the current dns config and the
// stored public IP. The first error is returned but all records are attempted.
func deleteDNS(ctx context.Context, api route53API, cfg *config.Config) error {
	if cfg.AWS == nil || len(cfg.AWS.DNSRecords) == 0 || cfg.DNS == nil {
		return nil
	}
	zoneID := cfg.AWS.ZoneID
	if zoneID == "" {
		zoneID = cfg.DNS.ZoneID
	}
	if zoneID == "" {
		return fmt.Errorf("cannot delete DNS records: no zone ID in state")
	}

	specByName := make(map[string]recordSpec)
	for _, spec := range planRecords(cfg.DNS, cfg.AWS.PublicIP) {
		specByName[spec.Name+"|"+spec.Type] = spec
	}

	var firstErr error
	for _, rec := range cfg.AWS.DNSRecords {
		spec, ok := specByName[rec.Name+"|"+rec.Type]
		if !ok {
			spec = recordSpec{Name: rec.Name, Type: rec.Type, Value: cfg.AWS.PublicIP, TTL: int64(cfg.DNS.TTL)}
		}
		if err := changeRecord(ctx, api, zoneID, r53types.ChangeActionDelete, spec); err != nil && firstErr == nil {
			firstErr = err
		}
	}
	cfg.AWS.DNSRecords = nil
	return firstErr
}

// swapDNS upserts every planned record to point at the current public IP,
// re-creating CNAME aliases. It auto-resolves the zone if absent and refreshes
// the tracked record list and FQDN in state.
func swapDNS(ctx context.Context, api route53API, cfg *config.Config) error {
	if cfg.DNS == nil || cfg.DNS.Domain == "" {
		return fmt.Errorf("dns swap requires a dns section with a domain")
	}
	if cfg.AWS == nil || cfg.AWS.PublicIP == "" {
		return fmt.Errorf("dns swap requires a current public IP in aws state")
	}
	zoneID := cfg.AWS.ZoneID
	if zoneID == "" {
		zoneID = cfg.DNS.ZoneID
	}
	if zoneID == "" {
		id, err := lookupZoneID(ctx, api, cfg.DNS.Domain)
		if err != nil {
			return err
		}
		zoneID = id
	}

	specs := planRecords(cfg.DNS, cfg.AWS.PublicIP)
	var records []config.DNSRecord
	for _, spec := range specs {
		if err := changeRecord(ctx, api, zoneID, r53types.ChangeActionUpsert, spec); err != nil {
			return err
		}
		records = append(records, config.DNSRecord{Name: spec.Name, Type: spec.Type})
	}
	cfg.AWS.ZoneID = zoneID
	cfg.AWS.FQDN = fqdn(cfg.DNS.Hostname, cfg.DNS.Domain)
	cfg.AWS.DNSRecords = records
	return nil
}

package aws

import (
	"context"
	"encoding/base64"
	"fmt"
	"io"
	"os"
	"os/exec"
	"syscall"
	"time"

	"github.com/aws/aws-sdk-go-v2/service/ec2"

	"github.com/gherlein/govirt/internal/config"
	"github.com/gherlein/govirt/internal/provider"
)

// Provider is the AWS EC2 VMProvider implementation. It provisions an instance
// through a CloudFormation stack and manages Route53 DNS records.
type Provider struct {
	// newClients constructs the AWS service clients for a region. It is a field
	// so tests can inject fakes without network access.
	newClients func(ctx context.Context, region string) (*clients, error)
	StackPoll  stackPoll
	Out        io.Writer
}

// New returns a Provider that builds clients from the default AWS credential
// chain.
func New() *Provider {
	return &Provider{
		newClients: loadClients,
		StackPoll:  defaultStackPoll,
		Out:        os.Stderr,
	}
}

// Name implements provider.VMProvider.
func (p *Provider) Name() string { return "aws" }

func (p *Provider) out() io.Writer {
	if p.Out != nil {
		return p.Out
	}
	return os.Stderr
}

func (p *Provider) clients(ctx context.Context, region string) (*clients, error) {
	if p.newClients == nil {
		p.newClients = loadClients
	}
	if region == "" {
		region = config.DefaultRegion
	}
	return p.newClients(ctx, region)
}

// Create provisions the EC2 instance: AMI lookup, VPC/subnet discovery, a
// CloudFormation stack carrying the base64 cloud-init UserData, then DNS
// records. All outputs are written to cfg.AWS.
func (p *Provider) Create(ctx context.Context, cfg *config.Config, cloudInitPath string) error {
	if cfg.VM == nil {
		return fmt.Errorf("config missing vm section")
	}
	name := cfg.VM.Name
	if err := config.ValidateName(name); err != nil {
		return err
	}

	userData, err := os.ReadFile(cloudInitPath)
	if err != nil {
		return fmt.Errorf("reading processed cloud-init: %w", err)
	}
	userDataB64 := base64.StdEncoding.EncodeToString(userData)

	cl, err := p.clients(ctx, cfg.VM.Region)
	if err != nil {
		return err
	}

	amiID, err := lookupAMI(ctx, cl.ssm, cfg.VM.OS)
	if err != nil {
		return err
	}

	net, err := ensureNetwork(ctx, cl.ec2, cfg.VM)
	if err != nil {
		return err
	}

	body, err := renderTemplate(templateParams{
		AMIID:        amiID,
		InstanceType: cfg.VM.InstanceType,
		SubnetID:     net.SubnetID,
		VpcID:        net.VpcID,
		UserDataB64:  userDataB64,
		SSHCidr:      cfg.VM.SSHCidr,
		WebCidr:      cfg.VM.WebCidr,
	})
	if err != nil {
		return err
	}

	stack := stackName(name)
	stackID, outputs, err := createStack(ctx, cl.cfn, stack, body, p.StackPoll)
	if err != nil {
		return err
	}

	cfg.AWS = &config.AWSState{
		PublicIP:      outputs.PublicIP,
		InstanceID:    outputs.InstanceID,
		StackID:       stackID,
		StackName:     stack,
		SecurityGroup: outputs.SecurityGroupID,
		AMIID:         amiID,
	}
	applyNetworkState(cfg.AWS, net)

	if err := createDNS(ctx, cl.route53, cfg, outputs.PublicIP); err != nil {
		return err
	}
	return nil
}

// Delete tears down DNS records, the CloudFormation stack, and any network
// resources govirt created, then clears cfg.AWS.
func (p *Provider) Delete(ctx context.Context, cfg *config.Config) error {
	if cfg.AWS == nil {
		return fmt.Errorf("VM not found: check 'govirt list' for available VMs")
	}
	if err := config.ValidateName(cfg.VM.Name); err != nil {
		return err
	}
	cl, err := p.clients(ctx, cfg.VM.Region)
	if err != nil {
		return err
	}

	if err := deleteDNS(ctx, cl.route53, cfg); err != nil {
		fmt.Fprintf(p.out(), "warning: deleting DNS records: %v\n", err)
	}
	if cfg.AWS.StackName != "" {
		if err := deleteStack(ctx, cl.cfn, cfg.AWS.StackName); err != nil {
			return err
		}
	}
	if err := cleanupNetwork(ctx, cl.ec2, cfg.AWS); err != nil {
		fmt.Fprintf(p.out(), "warning: cleaning up network resources: %v\n", err)
	}
	cfg.AWS = nil
	return nil
}

// Status reports the EC2 instance state and current public IP.
func (p *Provider) Status(ctx context.Context, cfg *config.Config) (*provider.VMStatus, error) {
	if cfg.AWS == nil || cfg.AWS.InstanceID == "" {
		return nil, fmt.Errorf("VM not found: check 'govirt list' for available VMs")
	}
	cl, err := p.clients(ctx, cfg.VM.Region)
	if err != nil {
		return nil, err
	}
	inst, err := describeInstance(ctx, cl.ec2, cfg.AWS.InstanceID)
	if err != nil {
		return nil, err
	}
	state, ip, created := instanceStatus(inst, cfg.VM.Name)
	return &provider.VMStatus{
		Name:      cfg.VM.Name,
		State:     state,
		IP:        ip,
		Provider:  p.Name(),
		CreatedAt: created,
	}, nil
}

// List returns all EC2 instances visible to the credentials, excluding
// terminated ones. govirt does not own a global registry of instances, so this
// reflects the account's running fleet in the configured region.
func (p *Provider) List(ctx context.Context) ([]provider.VMStatus, error) {
	cl, err := p.clients(ctx, config.DefaultRegion)
	if err != nil {
		return nil, err
	}
	out, err := cl.ec2.DescribeInstances(ctx, &ec2.DescribeInstancesInput{})
	if err != nil {
		return nil, fmt.Errorf("listing instances: %w", err)
	}
	var result []provider.VMStatus
	for _, r := range out.Reservations {
		for i := range r.Instances {
			inst := &r.Instances[i]
			name := instanceName(inst)
			state, ip, created := instanceStatus(inst, name)
			if state == "terminated" {
				continue
			}
			result = append(result, provider.VMStatus{
				Name:      name,
				State:     state,
				IP:        ip,
				Provider:  p.Name(),
				CreatedAt: created,
			})
		}
	}
	return result, nil
}

// Stop stops the instance (graceful guest shutdown).
func (p *Provider) Stop(ctx context.Context, cfg *config.Config) error {
	id, cl, err := p.instanceAndClients(ctx, cfg)
	if err != nil {
		return err
	}
	if _, err := cl.ec2.StopInstances(ctx, &ec2.StopInstancesInput{InstanceIds: []string{id}}); err != nil {
		return fmt.Errorf("stopping instance %s: %w", id, err)
	}
	return nil
}

// Start starts the instance.
func (p *Provider) Start(ctx context.Context, cfg *config.Config) error {
	id, cl, err := p.instanceAndClients(ctx, cfg)
	if err != nil {
		return err
	}
	if _, err := cl.ec2.StartInstances(ctx, &ec2.StartInstancesInput{InstanceIds: []string{id}}); err != nil {
		return fmt.Errorf("starting instance %s: %w", id, err)
	}
	return nil
}

// SSH replaces the current process with an interactive ssh session to the
// instance public IP, using the first configured user.
func (p *Provider) SSH(ctx context.Context, cfg *config.Config) error {
	if cfg.AWS == nil || cfg.AWS.PublicIP == "" {
		return fmt.Errorf("no public IP for %s: check 'govirt status %s'", cfg.VM.Name, cfg.VM.Name)
	}
	if len(cfg.VM.Users) == 0 {
		return fmt.Errorf("no users defined for %s", cfg.VM.Name)
	}
	user := cfg.VM.Users[0].Username
	sshPath, err := exec.LookPath("ssh")
	if err != nil {
		return fmt.Errorf("ssh not found: %w", err)
	}
	argv := []string{"ssh", "-o", "StrictHostKeyChecking=no", user + "@" + cfg.AWS.PublicIP}
	return syscall.Exec(sshPath, argv, os.Environ())
}

// SwapDNS implements provider.DNSSwapper: it points all tracked DNS records at
// the instance's current public IP, refreshing the IP from EC2 first.
func (p *Provider) SwapDNS(ctx context.Context, cfg *config.Config) error {
	if cfg.AWS == nil || cfg.AWS.InstanceID == "" {
		return fmt.Errorf("VM not found: check 'govirt list' for available VMs")
	}
	cl, err := p.clients(ctx, cfg.VM.Region)
	if err != nil {
		return err
	}
	inst, err := describeInstance(ctx, cl.ec2, cfg.AWS.InstanceID)
	if err != nil {
		return err
	}
	_, ip, _ := instanceStatus(inst, cfg.VM.Name)
	if ip != "" {
		cfg.AWS.PublicIP = ip
	}
	return swapDNS(ctx, cl.route53, cfg)
}

// instanceAndClients resolves the instance ID and AWS clients for lifecycle
// operations.
func (p *Provider) instanceAndClients(ctx context.Context, cfg *config.Config) (string, *clients, error) {
	if cfg.AWS == nil || cfg.AWS.InstanceID == "" {
		return "", nil, fmt.Errorf("VM not found: check 'govirt list' for available VMs")
	}
	cl, err := p.clients(ctx, cfg.VM.Region)
	if err != nil {
		return "", nil, err
	}
	return cfg.AWS.InstanceID, cl, nil
}

// instanceName returns the value of the instance's Name tag, falling back to its
// instance ID.
func instanceName(inst *ec2InstanceLike) string {
	for _, t := range inst.Tags {
		if t.Key != nil && *t.Key == "Name" && t.Value != nil {
			return *t.Value
		}
	}
	if inst.InstanceId != nil {
		return *inst.InstanceId
	}
	return ""
}

var (
	_ provider.VMProvider = (*Provider)(nil)
	_ provider.DNSSwapper = (*Provider)(nil)
)

