func TestSSMPath(t *testing.T) {
	cases := map[string]string{
		"ubuntu-24.04":      "/aws/service/canonical/ubuntu/server/24.04/stable/current/amd64/hvm/ebs-gp2/ami-id",
		"ubuntu-22.04":      "/aws/service/canonical/ubuntu/server/22.04/stable/current/amd64/hvm/ebs-gp2/ami-id",
		"ubuntu-20.04":      "/aws/service/canonical/ubuntu/server/20.04/stable/current/amd64/hvm/ebs-gp2/ami-id",
		"amazon-linux-2023": "/aws/service/ami-amazon-linux-latest/al2023-ami-kernel-default-x86_64",
		"amazon-linux-2":    "/aws/service/ami-amazon-linux-latest/amzn2-ami-hvm-x86_64-gp2",
		"debian-12":         "/aws/service/debian/release/12/latest/amd64",
		"debian-11":         "/aws/service/debian/release/11/latest/amd64",
	}
	for os, want := range cases {
		got, err := ssmPath(os)
		if err != nil {
			t.Errorf("ssmPath(%q): unexpected error %v", os, err)
			continue
		}
		if got != want {
			t.Errorf("ssmPath(%q) = %q, want %q", os, got, want)
		}
	}
	if _, err := ssmPath("windows-11"); err == nil {
		t.Error("expected error for unknown os")
	}
}

func TestRenderTemplate(t *testing.T) {
	b64 := base64.StdEncoding.EncodeToString([]byte("#cloud-config\n"))
	body, err := renderTemplate(templateParams{
		AMIID:        "ami-123",
		InstanceType: "t3.micro",
		SubnetID:     "subnet-1",
		VpcID:        "vpc-1",
		UserDataB64:  b64,
	})
	if err != nil {
		t.Fatalf("renderTemplate: %v", err)
	}
	for _, want := range []string{
		"AWS::EC2::SecurityGroup",
		"AWS::EC2::Instance",
		`"FromPort": 22`,
		`"FromPort": 80`,
		`"FromPort": 443`,
		`"ToPort": 443`,
		"0.0.0.0/0",
		b64,
		"ami-123",
		"subnet-1",
		"InstanceId",
		"PublicIP",
		"SecurityGroupId",
	} {
		if !strings.Contains(body, want) {
			t.Errorf("template missing %q\n%s", want, body)
		}
	}
}

func TestRenderTemplateCustomCidrs(t *testing.T) {
	body, err := renderTemplate(templateParams{
		AMIID: "ami-1", InstanceType: "t3.micro", SubnetID: "s", VpcID: "v",
		SSHCidr: "10.0.0.0/8", WebCidr: "192.168.0.0/16",
	})
	if err != nil {
		t.Fatal(err)
	}
	if !strings.Contains(body, "10.0.0.0/8") || !strings.Contains(body, "192.168.0.0/16") {
		t.Errorf("custom CIDRs not applied:\n%s", body)
	}
}

func TestStackName(t *testing.T) {
	if got := stackName("web-server"); got != "govirt-web-server" {
		t.Errorf("stackName = %q", got)
	}
}

func TestParseStackOutputs(t *testing.T) {
	outputs := []cfntypes.Output{
		{OutputKey: awssdk.String("InstanceId"), OutputValue: awssdk.String("i-abc")},
		{OutputKey: awssdk.String("PublicIP"), OutputValue: awssdk.String("54.1.2.3")},
		{OutputKey: awssdk.String("SecurityGroupId"), OutputValue: awssdk.String("sg-9")},
		{OutputKey: awssdk.String("Ignored"), OutputValue: awssdk.String("x")},
	}
	got := parseStackOutputs(outputs)
	if got.InstanceID != "i-abc" || got.PublicIP != "54.1.2.3" || got.SecurityGroupID != "sg-9" {
		t.Errorf("parseStackOutputs = %+v", got)
	}
}

// fakeEC2 implements ec2API with scripted responses and call recording.
type fakeEC2 struct {
	defaultVpcs []ec2types.Vpc
	allVpcs     []ec2types.Vpc
	subnets     map[string][]ec2types.Subnet

	createdVPC     bool
	createdSubnet  bool
	createdIGW     bool
	attachedIGW    bool
	createdRT      bool
	createdRoute   bool
	associatedRT   bool
	modifiedSubnet bool

	deleted []string
}

func (f *fakeEC2) DescribeVpcs(ctx context.Context, in *ec2.DescribeVpcsInput, _ ...func(*ec2.Options)) (*ec2.DescribeVpcsOutput, error) {
	for _, fl := range in.Filters {
		if awssdk.ToString(fl.Name) == "is-default" {
			return &ec2.DescribeVpcsOutput{Vpcs: f.defaultVpcs}, nil
		}
	}
	return &ec2.DescribeVpcsOutput{Vpcs: f.allVpcs}, nil
}

func (f *fakeEC2) DescribeSubnets(ctx context.Context, in *ec2.DescribeSubnetsInput, _ ...func(*ec2.Options)) (*ec2.DescribeSubnetsOutput, error) {
	var vpcID string
	for _, fl := range in.Filters {
		if awssdk.ToString(fl.Name) == "vpc-id" && len(fl.Values) > 0 {
			vpcID = fl.Values[0]
		}
	}
	return &ec2.DescribeSubnetsOutput{Subnets: f.subnets[vpcID]}, nil
}

func (f *fakeEC2) CreateVpc(ctx context.Context, in *ec2.CreateVpcInput, _ ...func(*ec2.Options)) (*ec2.CreateVpcOutput, error) {
	f.createdVPC = true
