// fakeRoute53 implements route53API recording every change.
type fakeRoute53 struct {
	zones   []r53types.HostedZone
	changes []r53Change
}

type r53Change struct {
	Action string
	Name   string
	Type   string
	Value  string
	TTL    int64
}

func (f *fakeRoute53) ListHostedZonesByName(ctx context.Context, in *route53.ListHostedZonesByNameInput, _ ...func(*route53.Options)) (*route53.ListHostedZonesByNameOutput, error) {
	return &route53.ListHostedZonesByNameOutput{HostedZones: f.zones}, nil
}

func (f *fakeRoute53) ChangeResourceRecordSets(ctx context.Context, in *route53.ChangeResourceRecordSetsInput, _ ...func(*route53.Options)) (*route53.ChangeResourceRecordSetsOutput, error) {
	for _, c := range in.ChangeBatch.Changes {
		rr := c.ResourceRecordSet
		value := ""
		if len(rr.ResourceRecords) > 0 {
			value = awssdk.ToString(rr.ResourceRecords[0].Value)
		}
		f.changes = append(f.changes, r53Change{
			Action: string(c.Action),
			Name:   awssdk.ToString(rr.Name),
			Type:   string(rr.Type),
			Value:  value,
			TTL:    awssdk.ToInt64(rr.TTL),
		})
	}
	return &route53.ChangeResourceRecordSetsOutput{}, nil
}

func TestPlanRecords(t *testing.T) {
	dns := &config.DNSConfig{
		Hostname:     "web",
		Domain:       "example.com",
		TTL:          300,
		IsApexDomain: true,
		CNAMEAliases: []string{"www"},
	}
	specs := planRecords(dns, "54.1.2.3")
	if len(specs) != 3 {
		t.Fatalf("expected 3 specs, got %d: %+v", len(specs), specs)
	}
	if specs[0].Name != "web.example.com." || specs[0].Type != "A" || specs[0].Value != "54.1.2.3" {
		t.Errorf("host A record wrong: %+v", specs[0])
	}
	if specs[1].Name != "example.com." || specs[1].Type != "A" {
		t.Errorf("apex A record wrong: %+v", specs[1])
	}
	if specs[2].Name != "www.example.com." || specs[2].Type != "CNAME" || specs[2].Value != "web.example.com." {
		t.Errorf("CNAME record wrong: %+v", specs[2])
	}
}

func TestCreateDNSTracksRecords(t *testing.T) {
	f := &fakeRoute53{zones: []r53types.HostedZone{
		{Id: awssdk.String("/hostedzone/Z123"), Name: awssdk.String("example.com.")},
	}}
	cfg := &config.Config{
		VM:  &config.VMConfig{Name: "web"},
		DNS: &config.DNSConfig{Hostname: "web", Domain: "example.com", TTL: 300, CNAMEAliases: []string{"www"}},
		AWS: &config.AWSState{},
	}
	if err := createDNS(context.Background(), f, cfg, "54.1.2.3"); err != nil {
		t.Fatal(err)
	}
	if cfg.AWS.ZoneID != "Z123" {
		t.Errorf("zone ID = %q", cfg.AWS.ZoneID)
	}
	if cfg.AWS.FQDN != "web.example.com." {
		t.Errorf("fqdn = %q", cfg.AWS.FQDN)
	}
	if len(cfg.AWS.DNSRecords) != 2 {
		t.Fatalf("tracked %d records, want 2: %+v", len(cfg.AWS.DNSRecords), cfg.AWS.DNSRecords)
	}
	for _, c := range f.changes {
		if c.Action != "UPSERT" {
			t.Errorf("expected UPSERT, got %q", c.Action)
		}
	}
}

