func TestSwapDNS(t *testing.T) {
	f := &fakeRoute53{}
	cfg := &config.Config{
		VM:  &config.VMConfig{Name: "web"},
		DNS: &config.DNSConfig{Hostname: "web", Domain: "example.com", TTL: 300, CNAMEAliases: []string{"www"}},
		AWS: &config.AWSState{PublicIP: "10.20.30.40", ZoneID: "Z123"},
	}
	if err := swapDNS(context.Background(), f, cfg); err != nil {
		t.Fatal(err)
	}
	var hostA bool
	for _, c := range f.changes {
		if c.Action != "UPSERT" {
			t.Errorf("swap should UPSERT, got %q", c.Action)
		}
		if c.Name == "web.example.com." && c.Type == "A" {
			hostA = true
			if c.Value != "10.20.30.40" {
				t.Errorf("host A points at %q, want 10.20.30.40", c.Value)
			}
		}
	}
	if !hostA {
		t.Error("missing host A record in swap")
	}
	if len(cfg.AWS.DNSRecords) != 2 {
		t.Errorf("swap should track 2 records, got %+v", cfg.AWS.DNSRecords)
	}
}

